#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *a = (long long*)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        long long *ans = (long long*)malloc(N * sizeof(long long));
        long long *stack = (long long*)malloc(N * sizeof(long long));
        int top = -1;
        for (int i = N-1; i >= 0; --i) {
            while (top >= 0 && stack[top] >= a[i]) top--;
            ans[i] = (top == -1) ? -1 : stack[top];
            stack[++top] = a[i];
        }
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%lld", ans[i]);
        }
        printf("\n");
        free(a); free(ans); free(stack);
    }
    return 0;
}

