for (let t = 0; t < T; t++) {
  const N = Number(data[idx++]);
  const a = new Array(N);
  for (let i = 0; i < N; i++) a[i] = Number(data[idx++]);
  const ans = new Array(N);
  const stack = [];
  for (let i = N - 1; i >= 0; i--) {
    while (stack.length && stack[stack.length - 1] >= a[i]) stack.pop();
    ans[i] = stack.length ? stack[stack.length - 1] : -1;
    stack.push(a[i]);
  }
  output.push(ans.join(' '));
}
